# In-memory mapping of task_id -> claim token, keyed under a session key.
# Session-scoped: a (worker_id, task_id) lookup. Sessions expire when the
# cookie does. We deliberately do not persist this across restarts —
# a UI restart drops claim tokens and the TTL sweep recovers stranded
# tasks (eden_dispatch.sweep).
_CLAIMS: dict[tuple[str, str], str] = {}


def _claim_key(worker_id: str, task_id: str) -> tuple[str, str]:
    return (worker_id, task_id)


